proof fn phi_1_external_body_set_to_seq_forward(s: Set<int>, e: int)
    requires
        s.finite(),
        s.contains(e),
    ensures
        s.to_seq().contains(e),
{
    element_in_finite_set_exists_in_set_to_seq(s, e);
}

proof fn phi_2_external_body_seq_to_set_reverse(s: Set<int>, e: int)
    requires
        s.finite(),
        s.to_seq().contains(e),
    ensures
        s.contains(e),
{
    element_in_seq_exists_in_original_finite_set(s, e);
}

proof fn phi_3_not_in_set_not_in_to_seq(s: Set<int>, e: int)
    requires
        s.finite(),
        !s.contains(e),
    ensures
        !s.to_seq().contains(e),
{
    if s.to_seq().contains(e) {
        element_in_seq_exists_in_original_finite_set(s, e);
    }
}
